Build the connection reference for an ARM template:
```python
def build_connection_ref(sub_id, location, api_name, connection_name):
    return {
        api_name: {
            'connectionId': f'/subscriptions/{sub_id}/resourceGroups/{{rgName}}/providers/Microsoft.Web/connections/{connection_name}',
            'connectionName': connection_name,
            'id': f'/subscriptions/{sub_id}/providers/Microsoft.Web/locations/{location}/managedApis/{api_name}',
        }
    }
```

Build an ApiConnection action from connector swagger:
```python
def build_api_action(action_name, connection_name, path, method='post', body=None):
    action = {
        'type': 'ApiConnection',
        'inputs': {
            'host': {
                'connection': {'name': f"@parameters('$connections')['{connection_name}']['connectionId']"}
            },
            'method': method,
            'path': path,
        },
        'runAfter': {},
    }
    if body:
        action['inputs']['body'] = body
    return {action_name: action}
```
